import{c as t,Q as n,j as i,m as a}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Effective context engineering for AI agents","description":"","frontmatter":{"url":"https://www.anthropic.com/engineering/effective-context-engineering-for-ai-agents","title":"Effective context engineering for AI agents","author":"Anthropic Applied AI Team","archived":"2026-05-27T00:00:00.000Z","domain":"anthropic.com","published":"2025-09-29T00:00:00.000Z","tags":["anthropic","context-engineering","prompt-engineering","llm-agents","long-horizon-tasks"],"word_count":"約 1,400 字"},"headers":[],"relativePath":"research/ai-articles/2025-09-29-effective-context-engineering-for-ai-agents.md","filePath":"research/ai-articles/2025-09-29-effective-context-engineering-for-ai-agents.md","lastUpdated":1779901665000}'),r={name:"research/ai-articles/2025-09-29-effective-context-engineering-for-ai-agents.md"};function o(l,e,s,c,h,g){return n(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="effective-context-engineering-for-ai-agents" tabindex="-1">Effective context engineering for AI agents <a class="header-anchor" href="#effective-context-engineering-for-ai-agents" aria-label="Permalink to &quot;Effective context engineering for AI agents&quot;">​</a></h1><blockquote><p><strong>來源</strong>：<a href="https://www.anthropic.com/engineering/effective-context-engineering-for-ai-agents" target="_blank" rel="noreferrer">anthropic.com</a><strong>作者</strong>：Prithvi Rajasekaran、Ethan Dixon、Carly Ryan、Jeremy Hadfield（Anthropic Applied AI）；貢獻者：Rafi Ayub、Hannah Moran、Cal Rueb、Connor Jennings <strong>發布日期</strong>：2025-09-29 <strong>收錄日期</strong>：2026-05-27</p></blockquote><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Context engineering 是 prompt engineering 的自然演進：從「找對詞彙和句式」轉向「什麼樣的 token 配置最能引導模型產生期望行為」。Anthropic 定義 context engineering 為「在 LLM inference 期間策劃並維護最佳 token 集合的策略」。核心原則：<strong>將 context 視為有限資源，邊際報酬遞減</strong>，目標是找到能最大化期望結果的最小高信號 token 集合。</p><hr><h2 id="context-engineering-vs-prompt-engineering" tabindex="-1">Context Engineering vs. Prompt Engineering <a class="header-anchor" href="#context-engineering-vs-prompt-engineering" aria-label="Permalink to &quot;Context Engineering vs. Prompt Engineering&quot;">​</a></h2><table tabindex="0"><thead><tr><th>面向</th><th>Prompt Engineering</th><th>Context Engineering</th></tr></thead><tbody><tr><td>焦點</td><td>單一 prompt 的用詞優化</td><td>整個 agent 互動中的 token 配置</td></tr><tr><td>範疇</td><td>單次推論</td><td>多輪 session、跨 context window</td></tr><tr><td>核心問題</td><td>「說什麼？」</td><td>「放什麼資訊、放在哪裡？」</td></tr></tbody></table><hr><h2 id="context-rot-與-attention-budget" tabindex="-1">Context Rot 與 Attention Budget <a class="header-anchor" href="#context-rot-與-attention-budget" aria-label="Permalink to &quot;Context Rot 與 Attention Budget&quot;">​</a></h2><p>隨著 context window 擴大，模型準確度會退化（<strong>context rot</strong>）。根源在 transformer 架構：模型需要處理所有 token 間 n² 的成對關係，context 越長，attention 越稀薄。結論：注入更多資訊不等於更好的結果。</p><hr><h2 id="有效-context-的主要組成" tabindex="-1">有效 Context 的主要組成 <a class="header-anchor" href="#有效-context-的主要組成" aria-label="Permalink to &quot;有效 Context 的主要組成&quot;">​</a></h2><h3 id="_1-system-prompts" tabindex="-1">1. System Prompts <a class="header-anchor" href="#_1-system-prompts" aria-label="Permalink to &quot;1. System Prompts&quot;">​</a></h3><ul><li>要具體（足以引導行為）又靈活（足以讓模型應對多種情境）</li><li>避免過於脆弱的 if-else 邏輯，也避免模糊的通用指示</li><li>找到能讓模型建立穩健啟發式規則的平衡點</li></ul><h3 id="_2-tools" tabindex="-1">2. Tools <a class="header-anchor" href="#_2-tools" aria-label="Permalink to &quot;2. Tools&quot;">​</a></h3><ul><li>工具集應<strong>最小化、無重疊、意圖明確</strong></li><li>設計良好的工具回傳 token 高效的資訊，同時鼓勵 agent 採取高效行為</li><li>避免功能模糊或重疊的工具，防止 agent 決策歧義</li></ul><h3 id="_3-examples-few-shot-prompting" tabindex="-1">3. Examples（Few-shot Prompting） <a class="header-anchor" href="#_3-examples-few-shot-prompting" aria-label="Permalink to &quot;3. Examples（Few-shot Prompting）&quot;">​</a></h3><ul><li>「Examples 是值千言的圖片」——示範期望行為比描述更有效</li><li>精選一組<strong>多樣、典型</strong>的範例，優於試圖枚舉所有邊緣案例</li><li>避免過度窮舉：邊緣案例清單反而稀釋注意力</li></ul><h3 id="_4-message-history" tabindex="-1">4. Message History <a class="header-anchor" href="#_4-message-history" aria-label="Permalink to &quot;4. Message History&quot;">​</a></h3><ul><li>視為動態狀態，需要主動管理而非被動累積</li><li>隨著對話延伸，應定期壓縮或精煉歷史記錄</li></ul><hr><h2 id="runtime-context-策略" tabindex="-1">Runtime Context 策略 <a class="header-anchor" href="#runtime-context-策略" aria-label="Permalink to &quot;Runtime Context 策略&quot;">​</a></h2><h3 id="just-in-time-retrieval" tabindex="-1">Just-in-Time Retrieval <a class="header-anchor" href="#just-in-time-retrieval" aria-label="Permalink to &quot;Just-in-Time Retrieval&quot;">​</a></h3><ul><li>Agent 維護輕量級 identifier，而非預先載入所有資料</li><li>執行任務時透過工具動態取得所需資訊</li><li>效仿人類認知模式：需要時才查閱，不是全部記住</li></ul><h3 id="hybrid-approaches" tabindex="-1">Hybrid Approaches <a class="header-anchor" href="#hybrid-approaches" aria-label="Permalink to &quot;Hybrid Approaches&quot;">​</a></h3><ul><li>結合預先取得（速度）與自主探索能力（靈活性）</li><li>根據任務特性在執行效率與 runtime 成本間取得平衡</li></ul><hr><h2 id="長期任務-long-horizon-tasks-技術" tabindex="-1">長期任務（Long-Horizon Tasks）技術 <a class="header-anchor" href="#長期任務-long-horizon-tasks-技術" aria-label="Permalink to &quot;長期任務（Long-Horizon Tasks）技術&quot;">​</a></h2><h3 id="_1-compaction-壓縮" tabindex="-1">1. Compaction（壓縮） <a class="header-anchor" href="#_1-compaction-壓縮" aria-label="Permalink to &quot;1. Compaction（壓縮）&quot;">​</a></h3><ul><li>摘要並壓縮對話歷史</li><li>保留關鍵決策，丟棄冗餘輸出</li><li>讓 agent 在接近 context 上限時仍能繼續有效工作</li></ul><h3 id="_2-structured-note-taking-結構化筆記" tabindex="-1">2. Structured Note-Taking（結構化筆記） <a class="header-anchor" href="#_2-structured-note-taking-結構化筆記" aria-label="Permalink to &quot;2. Structured Note-Taking（結構化筆記）&quot;">​</a></h3><ul><li>Agent 維護外部記憶文件（如 <code>progress.txt</code>、<code>notes.md</code>）</li><li>實現跨 context reset 的持久記憶</li><li>新 session 開始時先讀筆記，快速重建工作狀態</li></ul><h3 id="_3-sub-agent-architectures-子-agent-架構" tabindex="-1">3. Sub-Agent Architectures（子 agent 架構） <a class="header-anchor" href="#_3-sub-agent-architectures-子-agent-架構" aria-label="Permalink to &quot;3. Sub-Agent Architectures（子 agent 架構）&quot;">​</a></h3><ul><li>專業化 agent 各自處理範疇聚焦的任務，擁有乾淨的 context</li><li>將精煉後的摘要回傳主 agent</li><li>避免單一 agent context 過度膨脹</li></ul><hr><h2 id="核心指導原則" tabindex="-1">核心指導原則 <a class="header-anchor" href="#核心指導原則" aria-label="Permalink to &quot;核心指導原則&quot;">​</a></h2><blockquote><p><strong>找到能最大化期望結果的最小高信號 token 集合。</strong></p></blockquote><ul><li>每個加入 context 的 token 都有成本（attention 消耗）</li><li>過多 context 稀釋關鍵資訊，降低模型表現</li><li>「緊湊但資訊豐富」優於「全面但冗長」</li><li>與人類認知的類比：過多資訊導致認知過載，少而精的資訊促進清晰判斷</li></ul>',39)])])}const p=t(r,[["render",o]]);export{u as __pageData,p as default};
